+
+function getConditionalOptionDependencies(
+  usage: Usage,
+): OptionDependencies | undefined {
+  for (const term of usage) {
+    if (term.type === "option" && term.dependsOn) return term.dependsOn;
+    if (term.type === "optional" || term.type === "multiple") {
+      const dependencies = getConditionalOptionDependencies(term.terms);
+      if (dependencies) return dependencies;
+    } else if (term.type === "exclusive") {
+      for (const terms of term.terms) {
+        const dependencies = getConditionalOptionDependencies(terms);
+        if (dependencies) return dependencies;
+      }
+    }
+  }
+  return undefined;
+}
+
+function getOptionNames(usage: Usage): readonly string[] {
+  const names: string[] = [];
+  for (const term of usage) {
+    if (term.type === "option") names.push(...term.names);
+    else if (term.type === "optional" || term.type === "multiple") {
+      names.push(...getOptionNames(term.terms));
+    } else if (term.type === "exclusive") {
+      for (const terms of term.terms) names.push(...getOptionNames(terms));
+    }
+  }
+  return names;
+}
+
+function getConditionalStateValue(state: unknown): unknown {
+  if (Array.isArray(state)) return getConditionalStateValue(state[0]);
+  if (isDependencySourceState(state)) return getConditionalStateValue(state.result);
+  if (isDeferredParseState(state)) {
+    return getConditionalStateValue(state.preliminaryResult);
+  }
+  if (typeof state === "object" && state != null && "success" in state) {
+    const result = state as ValueParserResult<unknown>;
+    return result.success ? result.value : undefined;
+  }
+  return state;
+}
+
+function wasConditionalOptionProvided(
+  state: unknown,
+  parser: Parser<Mode, unknown, unknown>,
+): boolean {
+  return state !== undefined && state !== parser.initialState;
+}
+
+interface ConditionalOptionContext {
+  readonly parsers: ReadonlyMap<string | symbol, Parser<Mode, unknown, unknown>>;
+  readonly names: ReadonlyMap<string, string | symbol>;
+}
+
+function createConditionalOptionContext(
+  parserPairs: readonly [string | symbol, Parser<Mode, unknown, unknown>][],
+): ConditionalOptionContext {
+  const parsers = new Map<string | symbol, Parser<Mode, unknown, unknown>>();
+  const names = new Map<string, string | symbol>();
+  for (const [key, parser] of parserPairs) {
+    parsers.set(key, parser);
+    for (const name of getOptionNames(parser.usage)) names.set(name, key);
+  }
+  return { parsers, names };
+}
+
+function resolveConditionalOptionKey(
+  option: string,
+  context: ConditionalOptionContext,
+): string | symbol | undefined {
+  return context.parsers.has(option) ? option : context.names.get(option);
+}
+
+function isDependencyConditionSatisfied(
+  condition: OptionDependencyCondition,
+  states: Record<string | symbol, unknown>,
+  context: ConditionalOptionContext,
+): boolean {
+  const key = resolveConditionalOptionKey(condition.option, context);
+  if (key === undefined) return false;
+  const value = getConditionalStateValue(states[key]);
+  return Object.hasOwn(condition, "value")
+    ? value === condition.value
+    : Boolean(value);
+}
+
+function isConditionalOptionSatisfied(
+  dependencies: OptionDependencies,
+  states: Record<string | symbol, unknown>,
+  context: ConditionalOptionContext,
+): boolean {
+  const single = dependencies.option === undefined ? [] : [{
+    option: dependencies.option,
+    ...(Object.hasOwn(dependencies, "value") && { value: dependencies.value }),
+  }];
+  const allOf = [...single, ...(dependencies.allOf ?? [])];
+  const allSatisfied = allOf.every((condition) =>
+    isDependencyConditionSatisfied(condition, states, context)
+  );
+  const anyOf = dependencies.anyOf;
+  return allSatisfied && (anyOf === undefined || anyOf.some((condition) =>
+    isDependencyConditionSatisfied(condition, states, context)
+  ));
+}
+
+function getUnsatisfiedConditionalDependency(
+  dependencies: OptionDependencies,
+  states: Record<string | symbol, unknown>,
+  context: ConditionalOptionContext,
+): OptionDependencyCondition | undefined {
+  const conditions = [
+    ...(dependencies.option === undefined ? [] : [{
+      option: dependencies.option,
+      ...(Object.hasOwn(dependencies, "value") && { value: dependencies.value }),
+    }]),
+    ...(dependencies.allOf ?? []),
+    ...(dependencies.anyOf ?? []),
+  ];
+  return conditions.find((condition) =>
+    !isDependencyConditionSatisfied(condition, states, context)
+  );
+}
