+import { object } from "@optique/core/constructs";
+import { formatMessage } from "@optique/core/message";
+import {
+  conditionalOption,
+  flag,
+  option,
+  optionalWhen,
+  requiredWhen,
+} from "@optique/core/primitives";
+import { parseSync, suggestSync } from "@optique/core/parser";
+import { withDefault } from "@optique/core/modifiers";
+import { boolean, choice, string } from "@optique/core/valueparser";
+import assert from "node:assert/strict";
+import { describe, it } from "node:test";
+
+describe("conditional options", () => {
+  it("resolves a dependency by object key or option name", () => {
+    const parser = object({
+      mode: option("--mode", choice(["json", "text"])),
+      indent: requiredWhen({ option: "mode", value: "json" }, "--indent", string()),
+      output: requiredWhen({ option: "--mode", value: "text" }, "--output", string()),
+    });
+
+    assert.ok(parseSync(parser, ["--mode", "json", "--indent", "2"]).success);
+    assert.ok(parseSync(parser, ["--mode", "text", "--output", "file"]).success);
+  });
+
+  it("reports an unsatisfied required dependency using its CLI name and value", () => {
+    const parser = object({
+      mode: option("--mode", choice(["json", "text"])),
+      indent: requiredWhen({ option: "mode", value: "json" }, "--indent", string()),
+    });
+    const result = parseSync(parser, ["--mode", "text"]);
+
+    assert.ok(!result.success);
+    if (!result.success) {
+      const error = formatMessage(result.error);
+      assert.ok(error.includes("requires option"));
+      assert.ok(error.includes("--mode"));
+      assert.ok(error.includes("json"));
+    }
+  });
+
+  it("supports compound conditions and their empty-array semantics", () => {
+    const parser = object({
+      first: flag("--first"),
+      second: flag("--second"),
+      all: optionalWhen({ allOf: [] }, "--all", string()),
+      any: optionalWhen({ anyOf: [] }, "--any", string()),
+      either: optionalWhen({ anyOf: [{ option: "first" }, { option: "second" }] }, "--either", string()),
+    });
+
+    const suggestions = [...suggestSync(parser, [], "--")].map((s) => s.text);
+    assert.ok(suggestions.includes("--all"));
+    assert.ok(!suggestions.includes("--any"));
+    assert.ok(!suggestions.includes("--either"));
+    const enabled = [...suggestSync(parser, ["--first"], "--")].map((s) => s.text);
+    assert.ok(enabled.includes("--either"));
+  });
+
+  it("keeps non-required options parseable while hidden", () => {
+    const parser = object({
+      enabled: flag("--enabled"),
+      extra: optionalWhen("enabled", "--extra", string()),
+    });
+    const result = parseSync(parser, ["--extra", "value"]);
+
+    assert.ok(result.success);
+  });
+
+  it("rejects a dependent option when its explicitly falsy dependee is provided", () => {
+    const parser = object({
+      enabled: option("--enabled", boolean()),
+      extra: optionalWhen("enabled", "--extra", string()),
+    });
+    const result = parseSync(parser, ["--enabled=false", "--extra", "value"]);
+
+    assert.ok(!result.success);
+  });
+
+  it("retains dependency metadata through wrappers", () => {
+    const parser = object({
+      enabled: flag("--enabled"),
+      extra: withDefault(optionalWhen("enabled", "--extra", string()), "default"),
+    });
+    const suggestions = [...suggestSync(parser, [], "--")].map((s) => s.text);
+
+    assert.ok(!suggestions.includes("--extra"));
+  });
+
+  it("accepts a full dependency configuration in conditionalOption", () => {
+    const parser = object({
+      mode: option("--mode", choice(["on", "off"])),
+      detail: conditionalOption(
+        { option: "mode", value: "on", required: true },
+        "--detail",
+        string(),
+      ),
+    });
+
+    assert.ok(parseSync(parser, ["--mode", "on", "--detail", "full"]).success);
+  });
+});
