+import assert from "node:assert/strict";
+import { describe, it } from "node:test";
+
+describe("conditional options", () => {
+  it("resolves a dependency by object key or option name", () => {
+    const parser = object({
+      mode: option("--mode", choice(["json", "text"])),
+      indent: requiredWhen({ option: "mode", value: "json" }, "--indent", string()),
+      output: requiredWhen({ option: "--mode", value: "text" }, "--output", string()),
+    });
+
+    assert.ok(parseSync(parser, ["--mode", "json", "--indent", "2"]).success);
+    assert.ok(parseSync(parser, ["--mode", "text", "--output", "file"]).success);
+  });
+
+  it("reports an unsatisfied required dependency using its CLI name and value", () => {
+    const parser = object({
+      mode: option("--mode", choice(["json", "text"])),
+      indent: requiredWhen({ option: "mode", value: "json" }, "--indent", string()),
+    });
+    const result = parseSync(parser, ["--mode", "text"]);
+
+    assert.ok(!result.success);
+    if (!result.success) {
+      const error = formatMessage(result.error);
+      assert.ok(error.includes("requires option"));
+      assert.ok(error.includes("--mode"));
+      assert.ok(error.includes("json"));
+    }
+  });
+
+  it("supports compound conditions and their empty-array semantics", () => {
+    const parser = object({
+      first: flag("--first"),
+      second: flag("--second"),
+      all: optionalWhen({ allOf: [] }, "--all", string()),
+      any: optionalWhen({ anyOf: [] }, "--any", string()),
+      either: optionalWhen({ anyOf: [{ option: "first" }, { option: "second" }] }, "--either", string()),
+    });
+
+    const suggestions = [...suggestSync(parser, [], "--")].map((s) => s.text);
+    assert.ok(suggestions.includes("--all"));
+    assert.ok(!suggestions.includes("--any"));
+    assert.ok(!suggestions.includes("--either"));
